        return -1;

    /* PKCS7 padding */
    pad_val = (uint8_t)(XTEA_BLOCK_SIZE - (plaintext_len % XTEA_BLOCK_SIZE));
    padded_len = plaintext_len + pad_val;

    memcpy(padded, plaintext, plaintext_len);
    memset(padded + plaintext_len, pad_val, pad_val);

