    num_blocks = padded_len / XTEA_BLOCK_SIZE;

    for (i = 0; i < num_blocks; i++) {
        uint8_t block[XTEA_BLOCK_SIZE];
        uint32_t v[2];

        /* XOR plaintext block with previous ciphertext (or IV) */
        xor_blocks(block, padded + (i * XTEA_BLOCK_SIZE), prev_block, XTEA_BLOCK_SIZE);

        /* Encrypt block */
        memcpy(v, block, XTEA_BLOCK_SIZE);
        xtea_encrypt_block(v, key32);
        memcpy(packet->ciphertext + (i * XTEA_BLOCK_SIZE), v, XTEA_BLOCK_SIZE);

        /* Save for next CBC round */
        memcpy(prev_block, packet->ciphertext + (i * XTEA_BLOCK_SIZE), XTEA_BLOCK_SIZE);
    }

    packet->ciphertext_len = (uint16_t)padded_len;
    packet->total_len = (uint16_t)(XTEA_BLOCK_SIZE + padded_len);

