/* ============== Simple Key Derivation ============== */
/*
 * Derive a session key from a master key and a nonce/counter.
 * Useful for key rotation without storing multiple keys.
 */
void iot_derive_key(const uint8_t master_key[XTEA_KEY_SIZE],
                    uint32_t counter,
                    uint8_t derived_key[XTEA_KEY_SIZE])
{
    uint32_t mk[4];
    uint32_t v[2];

    memcpy(mk, master_key, XTEA_KEY_SIZE);

    v[0] = counter;
    v[1] = ~counter;
    xtea_encrypt_block(v, mk);
    memcpy(derived_key, v, XTEA_BLOCK_SIZE);

    v[0] = counter ^ 0xA5A5A5A5;
    v[1] = counter ^ 0x5A5A5A5A;
    xtea_encrypt_block(v, mk);
    memcpy(derived_key + XTEA_BLOCK_SIZE, v, XTEA_BLOCK_SIZE);

    memset(mk, 0, sizeof(mk));
}

